import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Mail, MessageSquare, ExternalLink, Send, Clock, User as UserIcon } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  useEffect(() => {
    if (id) loadData(id);
  }, [id]);

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
      const [d, h, allUsers, hierarchy, allReferents] = await Promise.all([
        DocumentService.getById(docId),
        HistoryService.getHistory(docId),
        UserService.getAll(),
        HierarchyService.getFullHierarchy(),
        ReferentService.getAll()
      ]);

      if (d) {
        setDoc(d);
        setHistory(h);

        // Lógica para recuperar correos de asignados y referentes desde la matriz
        const targetMicro = normalizeHeader(d.microprocess || '');
        const targetProject = normalizeHeader(d.project || '');
        let node = null;

        for (const p of Object.keys(hierarchy)) {
          if (normalizeHeader(p) === targetProject) {
            for (const m of Object.keys(hierarchy[p])) {
              for (const proc of Object.keys(hierarchy[p][m])) {
                const found = hierarchy[p][m][proc].find(n => normalizeHeader(n.name) === targetMicro);
                if (found) { node = found; break; }
              }
              if (node) break;
            }
          }
          if (node) break;
        }

        if (node) {
          const aEmails = (node.assignees || []).map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
          setAssigneeEmails(aEmails);

          const rEmails = (node.referentIds || []).map(rid => allReferents.find(ref => ref.id === rid)?.email).filter(e => e) as string[];
          setReferentEmails(rEmails);
        }
      }
    } catch (e) {
      console.error("Error cargando detalle:", e);
    } finally {
      setLoading(false);
    }
  };

  const handleAction = async (action: 'APPROVE' | 'REJECT') => {
    if (!doc || actionLoading) return;
    if (action === 'REJECT' && !comment) {
      alert("Por favor, ingrese un comentario para el rechazo.");
      return;
    }

    setActionLoading(true);
    try {
      await DocumentService.transitionState(
        doc.id, 
        user, 
        action, 
        comment || (action === 'APPROVE' ? 'Aprobado sin observaciones.' : 'Rechazado para correcciones.')
      );
      setComment('');
      await loadData(doc.id);
    } catch (e: any) {
      alert("Error: " + e.message);
    } finally {
      setActionLoading(false);
    }
  };

  const handleNotifyReferent = () => {
    if (!doc) return;
    const to = referentEmails.join(',');
    const subject = encodeURIComponent(`Revisión Técnica Requerida: ${doc.title}`);
    const body = encodeURIComponent(`Estimados referentes,\n\nSe requiere su revisión técnica para el documento "${doc.title}" (Versión ${doc.version}).\n\nSaludos,\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${to}&su=${subject}&body=${body}`, '_blank');
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;
  if (!doc) return <div className="p-8 text-center text-slate-500">Documento no encontrado.</div>;

  const config = STATE_CONFIG[doc.state];
  const isCoordinator = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 transition-colors">
        <ArrowLeft size={20} className="mr-2" /> Volver
      </button>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-start">
          <div>
            <div className="flex items-center gap-2 mb-2">
              <span className="px-2 py-1 bg-slate-100 text-slate-600 text-[10px] font-bold rounded uppercase">{doc.project}</span>
              <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${config.color}`}>{config.label}</span>
            </div>
            <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
            <p className="text-slate-500 mt-1">{doc.description}</p>
          </div>
          <div className="text-right">
            <p className="text-xs text-slate-400 font-bold uppercase">Versión Actual</p>
            <p className="text-xl font-mono font-bold text-indigo-600">{doc.version}</p>
          </div>
        </div>

        <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6 bg-slate-50/30">
          <div className="space-y-4">
            <h3 className="font-bold text-slate-800 flex items-center gap-2 text-sm uppercase">
              <Activity size={18} className="text-indigo-600" /> Información del Expediente
            </h3>
            <div className="grid grid-cols-2 gap-4 text-sm">
              <div>
                <p className="text-slate-400 font-medium">Macroproceso</p>
                <p className="font-semibold text-slate-700">{doc.macroprocess || '-'}</p>
              </div>
              <div>
                <p className="text-slate-400 font-medium">Proceso</p>
                <p className="font-semibold text-slate-700">{doc.process || '-'}</p>
              </div>
              <div>
                <p className="text-slate-400 font-medium">Microproceso</p>
                <p className="font-semibold text-slate-700">{doc.microprocess || '-'}</p>
              </div>
              <div>
                <p className="text-slate-400 font-medium">Tipo</p>
                <p className="font-semibold text-slate-700">{doc.docType || '-'}</p>
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <h3 className="font-bold text-slate-800 flex items-center gap-2 text-sm uppercase">
              <Mail size={18} className="text-indigo-600" /> Comunicación
            </h3>
            <div className="space-y-2">
              <p className="text-xs text-slate-500">Contactos identificados para este microproceso:</p>
              <div className="flex flex-wrap gap-2">
                {referentEmails.length > 0 ? (
                  <button 
                    onClick={handleNotifyReferent}
                    className="flex items-center gap-2 px-3 py-1.5 bg-white border border-indigo-200 text-indigo-600 rounded-lg text-xs font-bold hover:bg-indigo-50 transition-colors"
                  >
                    <Send size={14} /> Notificar Referentes ({referentEmails.length})
                  </button>
                ) : (
                  <span className="text-xs text-slate-400 italic">No hay referentes vinculados en la matriz.</span>
                )}
              </div>
            </div>
          </div>
        </div>

        {isCoordinator && doc.state !== DocState.APPROVED && (
          <div className="p-6 border-t border-slate-100 bg-white">
            <h3 className="font-bold text-slate-800 text-sm uppercase mb-4">Acciones de Coordinación</h3>
            <div className="space-y-4">
              <textarea 
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                placeholder="Observaciones de la revisión (Obligatorio para rechazos)..."
                className="w-full p-3 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none min-h-[80px]"
              />
              <div className="flex gap-3">
                <button 
                  onClick={() => handleAction('APPROVE')}
                  disabled={actionLoading}
                  className="flex items-center gap-2 px-6 py-2 bg-green-600 text-white rounded-lg font-bold text-sm hover:bg-green-700 disabled:opacity-50 transition-colors"
                >
                  <CheckCircle size={18} /> Aprobar Etapa
                </button>
                <button 
                  onClick={() => handleAction('REJECT')}
                  disabled={actionLoading}
                  className="flex items-center gap-2 px-6 py-2 bg-red-600 text-white rounded-lg font-bold text-sm hover:bg-red-700 disabled:opacity-50 transition-colors"
                >
                  <XCircle size={18} /> Rechazar
                </button>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <h3 className="font-bold text-slate-800 flex items-center gap-2 text-sm uppercase mb-6">
          <Clock size={18} className="text-indigo-600" /> Historial de Actividad
        </h3>
        <div className="space-y-6">
          {history.length === 0 ? (
            <p className="text-center text-slate-400 py-4 italic text-sm">Sin registros previos.</p>
          ) : (
            history.map((h, i) => (
              <div key={h.id} className="flex gap-4">
                <div className="flex flex-col items-center">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${i === 0 ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                    <UserIcon size={16} />
                  </div>
                  {i < history.length - 1 && <div className="w-0.5 h-full bg-slate-100 my-1"></div>}
                </div>
                <div className="pb-6">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="font-bold text-slate-800 text-sm">{h.userName}</span>
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{new Date(h.timestamp).toLocaleString()}</span>
                  </div>
                  <p className="text-sm font-semibold text-indigo-600">{h.action}</p>
                  {h.comment && <p className="text-sm text-slate-600 mt-2 p-3 bg-slate-50 rounded-lg border border-slate-100 italic">"{h.comment}"</p>}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

